INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('generalpolice-f3743df6-moex-00162', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-112-13504c0c', 'sub-generalpolice-f3743df6-02', NULL, 'single_choice', '「那天我們翻過雞籠山，居高臨下看見遠方的地平線，此時正冒出濃濃白煙，是美 國飛機剛轟炸過的基隆港。二戰已將近尾聲，從大人談話裡可聽出日軍正在節節敗 退。報紙上一再出現『決戰』字眼，他們面容竟絲毫不見憂心，不明白當了日本國 民五十年的臺灣人在心裡將自己擺在那一邊？回來以後，我好幾次夢見海上滿天都 是飛機，只慢慢移動甚至停留在海面，不時引發陣陣煙火……。又聽說有架美國 飛機落在山區，搜索隊回來時掏出好大的手錶，指針還運轉著，阿公看了有些傷感， 說：『美國手錶走的是美國時間，此時美國的家人還在等著他回去。』天未亮，隱 約聽到有女人哭泣的聲音，近午時聽說是收到未婚夫從遭攻擊的艦上，輾轉送出準 備好『全沒』的訣別書。」 下列敘述何者最接近主旨？', '["作者以孩童視角觀察戰爭中交迭的勝負", "作者疑惑大人對於日本政府的曖昧態度", "作者的家人對美軍相對期待並抱持同情", "作者的戰爭記憶中隱含了跨國族的創傷"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:44+00:00", "source_pdf_sha1": "12b40987f5c4", "answer_pdf_sha1": "0ddd4b93b580", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "305", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('generalpolice-f3743df6-moex-00163', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-112-13504c0c', 'sub-generalpolice-f3743df6-02', NULL, 'single_choice', '「高音的條件，是要有寬厚充足的氣力，讓聲音上去，有飽滿的氣力來襯托，才不 會高而危薄，終不能長久。」 下列選項，何者最切合文中所表達的旨趣？', '["為高必因丘陵，為下必因川澤", "無為其所不為，無欲其所不欲", "水之積也不厚，則其負大舟也無力", "致廣大而盡精微，極高明而道中庸"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:44+00:00", "source_pdf_sha1": "12b40987f5c4", "answer_pdf_sha1": "0ddd4b93b580", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "305", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('generalpolice-f3743df6-moex-00164', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-112-13504c0c', 'sub-generalpolice-f3743df6-02', NULL, 'single_choice', '「日本著名導演黑澤明的自傳用了一個奇怪的書名：《蝦蟆的油》。它來自日本的 一則民間傳說：有位醫生抓到一隻醜陋的蝦蟆，牠長有四隻前腳、六隻後腳。醫生 將蝦蟆裝進一個玻璃箱內，蝦蟆從鏡面的玻璃中，第一次看到自己醜陋的形象，嚇 得擠出一身油來。醫生收取這些油，用來治療病人的燒燙割傷，據說具有奇效。」 根據上文，下列何者最符合黑澤明傳記的命名旨趣？', '["作者自覺一生失敗難堪，猶如醜陋的蝦蟆，自慚形穢", "人世的險惡如醜陋的蝦蟆，令人驚駭莫名，細思極恐", "作者反思醜陋難堪的過往，透過書寫傳記以療傷止痛", "作者揭示自身難堪的經歷，盼能醫治讀者心靈的傷痛"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:44+00:00", "source_pdf_sha1": "12b40987f5c4", "answer_pdf_sha1": "0ddd4b93b580", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "305", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('generalpolice-f3743df6-moex-00165', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-112-13504c0c', 'sub-generalpolice-f3743df6-02', NULL, 'single_choice', '「紐曼認為大學是一個提供博雅教育，培育紳士的地方（雖然他也認為大學可以訓 練職業人才），他以為大學之目的在『傳授』學問而不在『發展』知識。他說：『如 果大學的目的在科學的與哲學的發明，那麼，我看不出為什麼大學應該有學生。』 紐曼之書為論大學之經典。他心中大學所應培育之紳士乃指通達而有修養與識見之 文化人。」 根據上文，最符合文中旨意的選項是：', '["大學最重要的目的在培育有創見的學者", "大學應以學生為重，提供優良博雅教育", "大學應該積極作為訓練職業人才的地方", "科學的與哲學的發明，是大學重要目的"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:44+00:00", "source_pdf_sha1": "12b40987f5c4", "answer_pdf_sha1": "0ddd4b93b580", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "305", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('generalpolice-f3743df6-moex-00166', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-112-13504c0c', 'sub-generalpolice-f3743df6-02', NULL, 'single_choice', '「2006年3月，設計博物館與BBC舉辦大眾票選，尋找英國最愛的設計符碼，紅 色電話亭名列前茅。儘管如今它幾乎失去了原有的功能，它的歷史、設計與過往日 常生活中的地位，也使它優雅地成為英國的國家象徵，也是公共性的體現。或許在 不久的將來，紅色電話亭也會跟文書軟體上代表儲存的磁碟片圖示一樣，晦澀而遙 遠。儘管原有的功能已成歷史，然而在符碼再次轉化與詮釋的過程中，似乎還是可 以發揮新意，這點也很英國。」 根據上文，「這點也很英國」的看法，下列選項何者正確？', '["希望能在保留傳統的同時，也發展出新的創見和意涵", "偏愛晦澀且遙遠的事物，因此希望保留古老的紅色電話亭", "強調優雅與日常，而紅色電話亭的設計正是符合這樣的要求", "重視傳統與科技的平衡，希望將傳統的文化以新興的科技保存下來"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:44+00:00", "source_pdf_sha1": "12b40987f5c4", "answer_pdf_sha1": "0ddd4b93b580", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "305", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('generalpolice-f3743df6-moex-00167', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-112-4b605adb', 'sub-generalpolice-f3743df6-03', NULL, 'essay', '甲公司為從事電腦散熱風扇及散熱片之專業製造商，其研發各項產品而
取得經濟部智慧財產局核准及公告之「A 散熱器」新型專利權及「B 散
熱器」新型專利權。乙公司未獲得甲公司同意或授權，竟製造侵害該「A
散熱器」新型專利權之產品銷售，乙公司則辯稱因甲公司於「A散熱器」
新型專利權產品上並未標示專利證書號數，故不知該產品有專利權。另
「B 散熱器」新型專利權因不具進步性，經舉發後，被智慧財產局撤銷
專利權，然於撤銷前，甲公司發現丙公司製造及販售侵害該「B 散熱器」
新型專利權之產品時，甲公司即申請取得智慧財產局所作成之無法否定
新穎性及進步性的新型專利技術報告，並向丙公司提起專利侵權訴訟。
該新型專利權被撤銷後，丙公司即主張甲公司所提起之專利侵權訴訟，
導致其受有損害，請求甲公司賠償。請附理由詳答下列問題：
請說明甲公司所有之專利權可排除他人為那些行為及其對乙公司請
求損害賠償之舉證責任為何？（10 分）
請說明新型專利技術報告之法律性質及甲公司應如何舉證始能對丙
公司免責？（14分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:44+00:00", "source_pdf_sha1": "dbd5b3389bfe", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "305", "s": "0806", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "智慧財產權法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('generalpolice-f3743df6-moex-00168', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-112-4b605adb', 'sub-generalpolice-f3743df6-03', NULL, 'essay', '甲作詞作曲家將其所創作之任何詞、曲音樂著作「專屬授權」予乙公司，
授權內容包括重製、公開演出、公開傳輸、改作、出版、發行等。「A歌」
之詞曲為甲所創作，而丙歌手未經同意或授權即在其售票演唱會上演唱
「A歌」。另甲亦具藝術天分，而將其所完成之臺灣著名觀光景點素描畫
作集結成「B 畫冊」出版，並以「非專屬授權」方式授權予丁印製及銷
售。不料，戊竟將「B 畫冊」掃描後並數位化後上傳至其個人網站供人
下載營利。請附理由詳答下列問題：
著作財產權專屬授權及非專屬授權之意義及法律效果為何？（12 分）
丙歌手之行為是否構成著作權之侵害以及何人得為訴訟上之主張？
（12分）
戊之行為是否構成著作權之侵害以及何人得為訴訟上之主張？（12分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:44+00:00", "source_pdf_sha1": "dbd5b3389bfe", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "305", "s": "0806", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "智慧財產權法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('generalpolice-f3743df6-moex-00169', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-112-4b605adb', 'sub-generalpolice-f3743df6-03', NULL, 'essay', '甲為專業美髮品牌公司，並為註冊「XYZ」商標之商標權人，指定用於
洗髮精等商品。乙公司未經甲公司授權使用，竟經由網路營業據點販賣
具有與該商標「XYZ」字樣完全相同之洗髮精，甲公司主張乙公司侵害
其商標權，乙公司則抗辯其所販賣之洗髮精，係經由甲公司所銷售流通
於市場後，而輾轉由 A髮型美容院販賣予乙公司。不久後，甲公司又在
網路上發現丙公司所生產及販賣的洗髮精，未經甲公司授權使用而在外
包裝及瓶裝上貼上甲公司所註冊之「XYZ」商標，甲公司亦主張丙公司
侵害其商標權，丙公司則抗辯其一直使用「XYZ」於洗髮精產品上，迄
今已經使用 30年，但未註冊商標，亦不知「XYZ」已由甲公司註冊而取
得商標權。另丁髮廊新開幕，於是在其廣告文宣、網頁及臉書粉絲團上，
宣傳來店即可參加抽獎活動，抽中即送「XYZ」洗髮精。甲公司亦主張
丁髮廊未經同意及授權便使用「XYZ」的商標於相關廣告文宣、網頁及
臉書粉絲團上而侵害其商標權。請附理由詳答下列問題：
乙公司是否得以「權利耗盡原則」抗辯之？（10 分）
丙公司是否得以「善意先使用」抗辯之？（15分）
丁髮廊是否得以「商標合理使用」抗辯之？（15 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:44+00:00", "source_pdf_sha1": "dbd5b3389bfe", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "305", "s": "0806", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "智慧財產權法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('generalpolice-f3743df6-moex-00170', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-112-bb28a373', 'sub-generalpolice-f3743df6-04', NULL, 'essay', '甲之子乙於民國（以下同）105年 1 月間擅自數次使用甲之印章、存摺，
先後提領甲於 A 銀行之存款計新臺幣 300 萬元，甲於翌年 2 月間發覺
後，即屢次催促乙速返還該款項，均未獲乙回應。嗣甲於109 年1 月間
過世，其財產由配偶丙、子女乙、丁繼承。試問丙、丁得依如何根據請
求乙返還上述款項？又如丙未得乙、丁之同意，單獨起訴請求乙返還上
述款項予全體繼承人，其主張是否有理？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:44+00:00", "source_pdf_sha1": "2354a362ddca", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "305", "s": "0801", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法與民事訴訟法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('generalpolice-f3743df6-moex-00171', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-112-bb28a373', 'sub-generalpolice-f3743df6-04', NULL, 'essay', '甲以其所有之 A屋設定最高限額新臺幣（以下同）1,000萬元、期限 20
年之抵押權於乙，以擔保甲未來向乙之借款後，即由甲向乙借款800 萬
